export type SupportedFrequencyLanguage = 'German' | 'Spanish' | 'French';

const MAPS: Record<SupportedFrequencyLanguage, Record<string, number>> = {
  German: DE_FREQUENCY,
  Spanish: ES_FREQUENCY,
  French: FR_FREQUENCY,
};

/**
 * Returns the corpus frequency rank of a word for the given language.
 * Lower rank = more frequent (1 = most common word in the corpus).
 * Returns null if the word is not in the frequency database.
 */
export function getFrequencyRank(lemma: string, language: string): number | null {
  const map = MAPS[language as SupportedFrequencyLanguage];
  if (!map) return null;
  return map[lemma.toLowerCase()] ?? null;
}

/**
 * Estimates a frequency rank for a word not in the database.
 * Uses a simple heuristic: longer words and compound nouns tend to be rarer.
 * Returns a rank in the range [30001, 99999] — beyond known corpus entries.
 *
 * This is used as a fallback when the LLM generates a word not in our database,
 * so new vocabulary still gets a plausible ordering signal without an LLM call.
 */
export function estimateFrequencyRank(lemma: string): number {
  const len = lemma.length;
  // Short words (≤4 chars) are usually common function words already in DB.
  // Long compound nouns (12+ chars) are typically rare.
  const lengthPenalty = Math.min(len * 1200, 60000);
  return 30000 + lengthPenalty;
}
